import{_ as a,c as t,o as i,ak as r,am as s}from"./chunks/framework.Dd0i9e2e.js";const p=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v2-44-1.md","filePath":"aireblock-releases/aireframe-v2-44-1.md","lastUpdated":1774453677000}'),o={name:"aireblock-releases/aireframe-v2-44-1.md"};function n(l,e,c,d,h,m){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+s+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.44.1<br><strong>Release Date:</strong> 4th March 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Add Ability to Regenerate AI Summary from Dashboard (FRAME-2418)</li><li>Improved Theme Caching (FRAME-2468)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Fixed Navigation Animation (FRAME-2406)</li><li>Fixed Structural Entity Picker Re-rendering (FRAME-2474)</li><li>Improved Visualisation Data Handling on Config Update (FRAME-2476)</li><li>Subject List Live Data Updates (FRAME-2477)</li><li>Data Extract List Now Shows All Extracts (FRAME-2484)</li><li>Monaco Editor Escape Key Behaviour (FRAME-2485)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="regenerate-ai-summary-from-dashboard-frame-2418" tabindex="-1">Regenerate AI Summary from Dashboard (FRAME-2418) <a class="header-anchor" href="#regenerate-ai-summary-from-dashboard-frame-2418" aria-label="Permalink to “Regenerate AI Summary from Dashboard (FRAME-2418)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Users can now regenerate the AI-generated summary displayed in the data summary widget directly from the dashboard. Previously, the summary was generated once and could not be refreshed without navigating away.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If your dashboard summary looks incorrect or you&#39;d like a clearer description of your data, you can now refresh it instantly with a single action — no need to reload the page or navigate away.</p></div><h4 id="improved-theme-caching-frame-2468" tabindex="-1">Improved Theme Caching (FRAME-2468) <a class="header-anchor" href="#improved-theme-caching-frame-2468" aria-label="Permalink to “Improved Theme Caching (FRAME-2468)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireFrame now caches the theme retrieved from AireTheme, reducing the number of repeated calls made to the theming service. The cache expires every 5–15 minutes, and if AireTheme is temporarily unavailable, the last successfully loaded theme will continue to be displayed rather than reverting to defaults.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your application theme will load faster and remain consistent even during brief interruptions to the theming service, ensuring a smoother and more reliable visual experience.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="fixed-navigation-animation-frame-2406" tabindex="-1">Fixed Navigation Animation (FRAME-2406) <a class="header-anchor" href="#fixed-navigation-animation-frame-2406" aria-label="Permalink to “Fixed Navigation Animation (FRAME-2406)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>An unexpected scrolling effect caused by the footer was visible when navigating from the home page to the configuration page. This animation artefact has been resolved.</p></div><h4 id="fixed-structural-entity-picker-re-rendering-frame-2474" tabindex="-1">Fixed Structural Entity Picker Re-rendering (FRAME-2474) <a class="header-anchor" href="#fixed-structural-entity-picker-re-rendering-frame-2474" aria-label="Permalink to “Fixed Structural Entity Picker Re-rendering (FRAME-2474)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The structural entity picker was continuously re-rendering and making repeated data fetch requests when empty. This has been corrected to prevent unnecessary processing and improve performance.</p></div><h4 id="improved-visualisation-data-handling-on-config-update-frame-2476" tabindex="-1">Improved Visualisation Data Handling on Config Update (FRAME-2476) <a class="header-anchor" href="#improved-visualisation-data-handling-on-config-update-frame-2476" aria-label="Permalink to “Improved Visualisation Data Handling on Config Update (FRAME-2476)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Previously, updating a visualisation&#39;s configuration triggered an attempt to delete all associated data sets, which caused timeouts and database lock issues for large tenants — particularly during imports. Data sets are now marked as stale instead of being deleted, and are recalculated on next read. This significantly reduces strain on the database and prevents disruption for active users.</p></div><h4 id="subject-list-live-data-updates-frame-2477" tabindex="-1">Subject List Live Data Updates (FRAME-2477) <a class="header-anchor" href="#subject-list-live-data-updates-frame-2477" aria-label="Permalink to “Subject List Live Data Updates (FRAME-2477)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Subject List V2 dashboards were not correctly receiving data update notifications, causing the interface to show a &quot;Data is loading&quot; message until the user manually refreshed. The fix ensures data is refetched on every relevant subscription notification, and reduces unnecessary per-subject subscriptions to lower server load.</p></div><h4 id="data-extract-list-now-shows-all-extracts-frame-2484" tabindex="-1">Data Extract List Now Shows All Extracts (FRAME-2484) <a class="header-anchor" href="#data-extract-list-now-shows-all-extracts-frame-2484" aria-label="Permalink to “Data Extract List Now Shows All Extracts (FRAME-2484)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The data extract list was incorrectly filtering to show only source data extracts, causing non-source extracts to be omitted. The filter has been corrected so all data extracts are now displayed as expected.</p></div><h4 id="monaco-editor-escape-key-behaviour-frame-2485" tabindex="-1">Monaco Editor Escape Key Behaviour (FRAME-2485) <a class="header-anchor" href="#monaco-editor-escape-key-behaviour-frame-2485" aria-label="Permalink to “Monaco Editor Escape Key Behaviour (FRAME-2485)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Pressing the Escape key whilst the autocomplete popup was active in the Monaco editor was incorrectly closing the editor entirely. Escape now correctly dismisses only the autocomplete popup, leaving the editor open.</p></div>',31)])])}const f=a(o,[["render",n]]);export{p as __pageData,f as default};
